import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.DEqXEGcv.js";const m=JSON.parse('{"title":"Desktop Environment","description":"","frontmatter":{},"headers":[],"relativePath":"en/docs/guide/desktop.md","filePath":"en/docs/guide/desktop.md"}'),n={name:"en/docs/guide/desktop.md"};function r(s,e,l,d,p,u){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="desktop-environment" tabindex="-1">Desktop Environment <a class="header-anchor" href="#desktop-environment" aria-label="Permalink to &quot;Desktop Environment&quot;">â€‹</a></h1><p>RDE provides a Windows-like web desktop experience, delivering a complete desktop environment in the browser.</p><h2 id="window-manager" tabindex="-1">Window Manager <a class="header-anchor" href="#window-manager" aria-label="Permalink to &quot;Window Manager&quot;">â€‹</a></h2><p>The window manager is the core component of the RDE desktop, managing the lifecycle, layout, and interaction of all application windows.</p><h3 id="window-operations" tabindex="-1">Window Operations <a class="header-anchor" href="#window-operations" aria-label="Permalink to &quot;Window Operations&quot;">â€‹</a></h3><ul><li><strong>Drag to move</strong>: Hold the title bar to drag windows anywhere</li><li><strong>Resize</strong>: Drag window edges to resize</li><li><strong>Maximize</strong>: Double-click title bar or click maximize button</li><li><strong>Minimize</strong>: Click minimize button, window goes to taskbar</li><li><strong>Close</strong>: Click close button or use keyboard shortcut</li></ul><h3 id="window-types" tabindex="-1">Window Types <a class="header-anchor" href="#window-types" aria-label="Permalink to &quot;Window Types&quot;">â€‹</a></h3><p>RDE supports three window types:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Use Case</th></tr></thead><tbody><tr><td>Component</td><td>Svelte component rendered directly</td><td>File manager, settings, and native apps</td></tr><tr><td>iframe</td><td>Embedded external page</td><td>Web apps, third-party services</td></tr><tr><td>Popup</td><td>Modal/non-modal dialog</td><td>Confirm dialogs, property panels</td></tr></tbody></table><h3 id="multi-window-management" tabindex="-1">Multi-Window Management <a class="header-anchor" href="#multi-window-management" aria-label="Permalink to &quot;Multi-Window Management&quot;">â€‹</a></h3><ul><li>Multiple windows can be open simultaneously with automatic z-index management</li><li>Clicking a window brings it to the front</li><li>Drag-and-drop data transfer between windows</li></ul><h2 id="taskbar" tabindex="-1">Taskbar <a class="header-anchor" href="#taskbar" aria-label="Permalink to &quot;Taskbar&quot;">â€‹</a></h2><p>The taskbar at the bottom of the screen provides:</p><ul><li><strong>App icons</strong>: Quick-launch shortcuts for common apps</li><li><strong>Open windows</strong>: Click to switch or minimize/restore windows</li><li><strong>System tray</strong>: Time, notifications, network status, etc.</li><li><strong>Start menu</strong>: List of all installed applications</li></ul><h2 id="context-menu" tabindex="-1">Context Menu <a class="header-anchor" href="#context-menu" aria-label="Permalink to &quot;Context Menu&quot;">â€‹</a></h2><p>Desktop and file manager support context menu operations:</p><ul><li>New file/folder</li><li>Paste, refresh</li><li>Change wallpaper</li><li>Display settings</li></ul><h2 id="multi-user-support" tabindex="-1">Multi-User Support <a class="header-anchor" href="#multi-user-support" aria-label="Permalink to &quot;Multi-User Support&quot;">â€‹</a></h2><p>RDE supports concurrent multi-user access:</p><ul><li>Each user has an independent desktop space</li><li>File system is isolated per user</li><li>Terminal sessions are isolated per user</li><li>Linux system users are created automatically</li></ul><p>See <a href="/en/docs/guide/users.html">User Management</a> for details.</p>',21)])])}const h=t(n,[["render",r]]);export{m as __pageData,h as default};
